const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');

// Set up upload directory and allowed file types
const uploadDir = 'public/uploads';
const allowedTypes = {
  image: ['image/jpeg', 'image/png', 'image/gif', 'image/svg+xml'],
  document: ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'],
  archive: ['application/zip']
};

// Set up multer with storage and file filter
const upload = multer({
  dest: uploadDir,
  limits: { fileSize: null }, // enterprise users have no size limit
  fileFilter(req, file, cb) {
    const fileType = path.extname(file.originalname).split('.')[1].toLowerCase();
    if (allowedTypes[fileType] && allowedTypes[fileType].includes(file.mimetype)) {
      return cb(null, true);
    }
    return cb(new Error('Invalid file type'));
  }
});

// Set up thumbnail generation
const sharp = require('sharp');
const generateThumbnail = async (filePath) => {
  try {
    const filename = path.basename(filePath);
    const thumbPath = `${uploadDir}/thumbnails/${filename}`;
    await sharp(filePath).resize(200, 200).toFile(thumbPath);
  } catch (err) {
    console.error(err);
  }
};

// Set up Express route for file upload
const router = express.Router();

router.post('/upload', upload.array('files'), async (req, res) => {
  try {
    const files = req.files;
    if (!files.length) return res.status(400).send({ error: 'No files uploaded' });

    // Process each file
    for (const file of files) {
      const fileType = path.extname(file.originalname).split('.')[1].toLowerCase();
      let filePath;

      switch (fileType) {
        case 'image':
          await generateThumbnail(file.path);
          break;
        case 'document':
          filePath = `${uploadDir}/${Date.now()}_${file.originalname}`;
          fs.copyFileSync(file.path, filePath);
          break;
        case 'archive':
          // Archive extraction is not allowed for security reasons
          return res.status(400).send({ error: 'Archive extraction is not allowed' });
      }

      // Store file in database or perform other actions as needed
    }

    res.send({ success: true, files: files.map((file) => ({ name: file.originalname, path: `${uploadDir}/${file.filename}` })) });
  } catch (err) {
    console.error(err);
    res.status(500).send({ error: 'Internal Server Error' });
  }
});

module.exports = router;